+// ---------------------------------------------------------------------------
+// Tracing helpers
+// ---------------------------------------------------------------------------
+
+fn emit_read_trace(data_key: &str, retries: u32) {
+    if retries > 0 {
+        tracing::debug!(
+            target: "fsqlite.left_right",
+            data_key,
+            retries,
+            "left_right_read retried"
+        );
+    } else {
+        tracing::trace!(
+            target: "fsqlite.left_right",
+            data_key,
+            retries = 0u32,
+            "left_right_read"
+        );
+    }
+}
+
+fn emit_swap_trace(swap_count: u32) {
+    tracing::debug!(
+        target: "fsqlite.left_right",
+        swap_count,
+        "left_right_swap"
+    );
+}
