+            // Simulate being in a read critical section.
+            while !do_q_r.load(Ordering::Acquire) {
+                std::hint::spin_loop();
+            }
+            h.quiescent();
+            // Keep handle alive a bit longer.
+            thread::sleep(Duration::from_millis(10));
+            drop(h);
+        });
